// Pega todos os itens do Google Sheets
const items = $input.all();

// Filtra e extrai apenas Titulo que não está vazio
const ideiasAnteriores = items
  .filter(item => item.json.titulo) // filtra apenas se tiver Titulo
  .map(item => ({
    titulo: item.json.titulo // pega apenas o titulo
  }));

// Retorna apenas total de ideias anteriores e ideias completas (somente títulos)
return [{
  json: {
    total_ideias_anteriores: ideiasAnteriores.length,
    ideias_completas: ideiasAnteriores
  }
}];

const dataAgora = new Date();
const yyyy = dataAgora.getFullYear();
const mm = String(dataAgora.getMonth() + 1).padStart(2, '0');
const dd = String(dataAgora.getDate()).padStart(2, '0');
const hh = String(dataAgora.getHours()).padStart(2, '0');
const min = String(dataAgora.getMinutes()).padStart(2, '0');
const ss = String(dataAgora.getSeconds()).padStart(2, '0');
const rand = Math.floor(Math.random() * 1000).toString().padStart(3, '0');

return items.map((item, i) => {
  const id_post = `post_instagram_${yyyy}${mm}${dd}_${hh}${min}${ss}_${rand}_${i+1}`;
  return {
    json: {
      id_post,
      Título: item.json.titulo,
      Briefing: item.json.briefing,
      Status: item.json.status
    }
  };
});

