// Extrai e parseia os briefings PREMIUM gerados pela IA

const items = $input.all();
const briefings = [];

for (const item of items) {
  try {
    // Tenta acessar o output da IA
    let rawOutput = item.json.output || item.json.text || item.json;

    // Se for string, faz o parse
    if (typeof rawOutput === 'string') {
      // Remove possíveis prefixos como "json[" e sufixos como "]"
      rawOutput = rawOutput
        .replace(/^json\[?\n?/i, '')  // Remove "json[" no início
        .replace(/\]$/, '')            // Remove "]" no final
        .replace(/```json\n?/g, '')    // Remove markdown
        .replace(/```\n?/g, '')
        .trim();

      // Tenta adicionar colchetes caso estejam faltando
      if (!rawOutput.startsWith('[') && rawOutput.startsWith('{')) {
        rawOutput = '[' + rawOutput + ']';
      }

      // Parse do JSON
      const parsed = JSON.parse(rawOutput);

      // Se parsed for array, adiciona cada item
      if (Array.isArray(parsed)) {
        briefings.push(...parsed);
      } else {
        briefings.push(parsed);
      }
    } 
    // Se já for objeto/array
    else if (Array.isArray(rawOutput)) {
      briefings.push(...rawOutput);
    } else if (typeof rawOutput === 'object') {
      briefings.push(rawOutput);
    }

  } catch (error) {
    console.error('Erro ao processar item:', error.message);
    console.error('Raw output:', item.json.output || item.json.text || item.json);
    // Continua processando outros items mesmo se um falhar
  }
}

// Valida se temos briefings
if (briefings.length === 0) {
  throw new Error('Nenhum briefing foi extraído. Verifique o formato da resposta da IA.');
}

// Formata data e hora no padrão brasileiro (fora do loop para usar uma vez)
const agora = new Date();
const dia = String(agora.getDate()).padStart(2, '0');
const mes = String(agora.getMonth() + 1).padStart(2, '0');
const ano = agora.getFullYear();
const hora = String(agora.getHours()).padStart(2, '0');
const minuto = String(agora.getMinutes()).padStart(2, '0');
const segundo = String(agora.getSeconds()).padStart(2, '0');
const dataHoraFormatada = `${dia}/${mes}/${ano} ${hora}:${minuto}:${segundo}`;

// Retorna cada briefing como um item separado com validação
return briefings.map((briefing, index) => {
  // Validação básica
  if (!briefing.Título && !briefing.titulo) {
    console.warn(`Briefing ${index + 1} sem título, pulando...`);
    return null;
  }

  if (!briefing.Briefing && !briefing.briefing) {
    console.warn(`Briefing ${index + 1} sem conteúdo, pulando...`);
    return null;
  }

  return {
    json: {
      titulo: briefing.Título || briefing.titulo,
      briefing: briefing.Briefing || briefing.briefing,
      status: briefing.Status || briefing.status || 'Aguardando',
      // Metadados úteis para rastreamento
      gerado_em: dataHoraFormatada,
      briefing_numero: index + 1,
      total_briefings: briefings.length
    }
  };
}).filter(item => item !== null); // Remove items inválidos

