// Processa artigos criados pela Agente IA 2

const items = $input.all();
const artigos = [];

for (const item of items) {
  try {
    // Tenta acessar o output da IA
    let rawOutput = item.json.output || item.json.text || item.json;

    // Se for string, faz o parse
    if (typeof rawOutput === 'string') {
      // Remove markdown code blocks e prefixos
      rawOutput = rawOutput
        .replace(/```json\n?/g, '')
        .replace(/```\n?/g, '')
        .replace(/^json\n?/i, '')
        .trim();

      // Parse do JSON
      const parsed = JSON.parse(rawOutput);
      artigos.push(parsed);
    } 
    // Se já for objeto
    else if (typeof rawOutput === 'object' && !Array.isArray(rawOutput)) {
      artigos.push(rawOutput);
    }

  } catch (error) {
    console.error('Erro ao processar artigo:', error.message);
    console.error('Raw output:', item.json.output || item.json.text || item.json);

    // Tenta salvar mesmo com erro (para debug)
    artigos.push({
      erro: true,
      mensagem: error.message,
      raw_output: item.json.output || item.json.text || item.json,
      briefing_original: item.json.titulo || 'Desconhecido'
    });
  }
}

// Valida se temos artigos
if (artigos.length === 0) {
  throw new Error('Nenhum artigo foi extraído. Verifique o formato da resposta da IA.');
}

// Formata data e hora no padrão brasileiro
const agora = new Date();
const dia = String(agora.getDate()).padStart(2, '0');
const mes = String(agora.getMonth() + 1).padStart(2, '0');
const ano = agora.getFullYear();
const hora = String(agora.getHours()).padStart(2, '0');
const minuto = String(agora.getMinutes()).padStart(2, '0');
const segundo = String(agora.getSeconds()).padStart(2, '0');
const dataHoraFormatada = `${dia}/${mes}/${ano} ${hora}:${minuto}:${segundo}`;

// Retorna cada artigo como um item separado
return artigos.map((artigo, index) => {
  // Se teve erro, retorna o erro
  if (artigo.erro) {
    return {
      json: artigo
    };
  }

  // Validação básica
  if (!artigo.titulo) {
    console.warn(`Artigo ${index + 1} sem título`);
  }

  if (!artigo.artigo_completo) {
    console.warn(`Artigo ${index + 1} sem conteúdo`);
  }

  return {
    json: {
      // Dados do artigo
      titulo: artigo.titulo || 'Sem título',
      artigo_completo: artigo.artigo_completo || '',
      resumo_executivo: artigo.resumo_executivo || '',
      palavras: artigo.palavras || 0,

      // Fontes
      fontes: artigo.fontes || [],
      total_fontes: (artigo.fontes || []).length,

      // Metadados
      criado_em: dataHoraFormatada,
      artigo_numero: index + 1,

      // Validação de qualidade
      qualidade: {
        tem_titulo: !!artigo.titulo,
        tem_conteudo: !!artigo.artigo_completo,
        tem_fontes: (artigo.fontes || []).length >= 5,
        palavras_ok: (artigo.palavras || 0) >= 2500,
        aprovado: !!(
          artigo.titulo && 
          artigo.artigo_completo && 
          (artigo.fontes || []).length >= 5 &&
          (artigo.palavras || 0) >= 2500
        )
      }
    }
  };
});
